vector<long long> solve(vector<long long> nums) {
    unordered_map<long long, long long> prefix_rem;
    prefix_rem[0] = -1;
    long long sum = 0;
    vector<pair<long long, long long>> intervals;

    for (long long i = 0; i < nums.size(); ++i) {
        sum += nums[i];
        long long rem = sum % nums.size();
        if (rem < 0) rem += nums.size();

        if (prefix_rem.find(rem) != prefix_rem.end()) {
            long long start = prefix_rem[rem] + 1;
            intervals.emplace_back(start, i);
        }
        prefix_rem[rem] = i;
    }

    // Merge intervals and calculate the remaining sum
    if (intervals.empty()) {
        return nums;
    }

    // Sort intervals by start time
    sort(intervals.begin(), intervals.end());

    vector<pair<long long, long long>> merged;
    for (auto &interval : intervals) {
        if (merged.empty() || interval.first > merged.back().second) {
            merged.push_back(interval);
        } else {
            merged.back().second = max(merged.back().second, interval.second);
        }
    }

    vector<long long> result;
    long long last = 0;
    for (auto &m : merged) {
        for (long long i = last; i < m.first; ++i) {
            result.push_back(nums[i]);
        }
        last = m.second + 1;
    }
    for (long long i = last; i < nums.size(); ++i) {
        result.push_back(nums[i]);
    }

    if (result.size() < nums.size()) {
        return solve(result);
    } else {
        return result;
    }
}
